    e=e:gsub('[^'..b..'=]','')
    local t={}
    for i=1,#e,4 do
        local a={}
        for j=0,3 do
            local c=e:sub(i+j,i+j)
            a[j+1]=c~='=' and b:find(c,1,true)-1 or nil
        end
        local v=(a[1]or 0)*262144+(a[2]or 0)*4096+(a[3]or 0)*64+(a[4]or 0)
        t[#t+1]=string.char(math.floor(v/65536))
        if a[3]then t[#t+1]=string.char(math.floor((v%65536)/256))end
        if a[4]then t[#t+1]=string.char(v%256)end
    end
